def p(g):
    # helper to check full lines
    def full_row(shape, r, w, h):
        return all((r, c) in shape for c in range(w))
    def full_col(shape, c, w, h):
        return all((r, c) in shape for r in range(h))
    # generate patterns
    def L_patterns(w, h):
        return [
            {(0, c) for c in range(w)} | {(r, w-1) for r in range(1, h)},
            {(0, c) for c in range(w)} | {(r, 0) for r in range(1, h)},
            {(h-1, c) for c in range(w)} | {(r, w-1) for r in range(h-1)},
            {(h-1, c) for c in range(w)} | {(r, 0) for r in range(h-1)},
        ]
    def U_patterns(w, h):
        if h < 2 or w < 2: return []
        return [
            {(0, c) for c in range(w)} | {(r, 0) for r in range(1, h)} | {(r, w-1) for r in range(1, h)},
            {(h-1, c) for c in range(w)} | {(r, 0) for r in range(h-1)} | {(r, w-1) for r in range(h-1)},
            {(r, 0) for r in range(h)} | {(0, c) for c in range(1, w)} | {(h-1, c) for c in range(1, w)},
            {(r, w-1) for r in range(h)} | {(0, c) for c in range(w-1)} | {(h-1, c) for c in range(w-1)},
        ]
    def H_patterns(w, h):
        pats = []
        if h >= 3:
            mid = h // 2
            pats.append({(r, 0) for r in range(h)} | {(r, w-1) for r in range(h)} | {(mid, c) for c in range(1, w-1)})
        if w >= 3:
            mid = w // 2
            pats.append({(0, c) for c in range(w)} | {(h-1, c) for c in range(w)} | {(r, mid) for r in range(1, h-1)})
        return pats

    visited = [[False]*len(g[0]) for _ in range(len(g))]
    out = [r[:] for r in g]
    from collections import deque
    H = len(g); W = len(g[0])
    for i in range(H):
        for j in range(W):
            if g[i][j] == 3 and not visited[i][j]:
                q = deque([(i,j)])
                visited[i][j] = 1
                comp = [(i,j)]
                while q:
                    r,c = q.popleft()
                    for dr,dc in ((1,0),(-1,0),(0,1),(0,-1)):
                        nr,nc = r+dr, c+dc
                        if 0<=nr<H and 0<=nc<W and g[nr][nc]==3 and not visited[nr][nc]:
                            visited[nr][nc]=1
                            q.append((nr,nc))
                            comp.append((nr,nc))
                mr = min(r for r,_ in comp)
                mc = min(c for _,c in comp)
                shape = {(r-mr, c-mc) for r,c in comp}
                w = max(c for _,c in comp) - mc + 1
                h = max(r for r,_ in comp) - mr + 1
                color = None
                # try L first
                for pat in L_patterns(w,h):
                    if shape == pat:
                        color = 1
                        break
                if color is None:
                    for pat in U_patterns(w,h):
                        if shape == pat:
